import React, { useEffect, useState } from 'react'
import { Link, useParams } from 'react-router-dom'
import { DummyResumeData } from '../assets/assets'
import { ArrowLeftIcon, Briefcase, ChevronLeft, ChevronRight, FileText, FolderIcon, GraduationCap, Sparkle, User } from 'lucide-react'
import PersonalInfoForm from '../Components/PersonalInfoForm.jsx'
import ResumePreview from '../Components/ResumePreview.jsx'

const ResumeBuilder = () => {
  const { resumeId } = useParams()

  const [resumeData, setResumeData] = useState({
    _id: '',
    title: '',
    personal_info: {},
    professional_summary: '',
    experience: [],
    education: [],
    project: [],
    skills: [],
    template: 'classic',
    accent_color: 'grey',
    public: false,

  })

  const loadExistingResume = async () => {
    if (DummyResumeData && DummyResumeData._id === resumeId) {
      setResumeData(DummyResumeData);
      document.title = DummyResumeData.title;
    }
  }
  const [activeSectionIndex, setActiveSectionIndex] = useState(0)
  const [removeBackground, setRemoveBackground] = useState(false);

  const sections = [
    { id: 'personal', name: 'Personal Info', icon: User },
    { id: 'summary', name: 'Summary', icon: FileText },
    { id: 'experience', name: 'Experience', icon: Briefcase },
    { id: 'education', name: 'Education', icon: GraduationCap },
    { id: 'project', name: 'Project', icon: FolderIcon },
    { id: 'skills', name: 'Skills', icon: Sparkle },

  ]

  const activeSection = sections[activeSectionIndex];

  useEffect(() => {
    loadExistingResume();
  }, []);

  return (
    <div>
      <div className="">
        <Link to={'/app'} className='inline-flex gap-3 items-center text-slate-500 dark:text-slate-400 transition-all'>
          <ArrowLeftIcon className='size-8 mr-2' />Back To Dashboard
        </Link>
      </div>
      <div className="max-w-7xl mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          {/* Left Panel - Form */}
          <div className='relative lg:col-span-2 rounded-lg overflow-hidden'>
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
              {/* progress bar using activeSectionIndex */}
              <div className="absolute top-0 left-0 right-0 h-1 bg-gray-200 dark:bg-gray-700" />
              <div className="absolute top-0 left-0 h-1 bg-gradient-to-r from-green-400 to-blue-500 transition-all duration-[2000ms]"
                style={{
                  width: `${(activeSectionIndex / sections.length) * 100}%`
                }} />
              {/* Section Navigation */}
              <div className="flex justify-between items-center px-4 py-2 border-b border-gray-200 dark:border-gray-700">
                <div className="">

                </div>
                <div className="flex space-x-2">
                  {activeSectionIndex !== 0 && (
                    <button onClick={() => setActiveSectionIndex((prevIndex) => Math.max(prevIndex - 1, 0))} className="flex items-center px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-md hover:bg-gray-300 dark:hover:bg-gray-600 transition-all" disabled={activeSectionIndex === 0}>
                      <ChevronLeft className="size-4" />
                      Previous
                    </button>
                  )}
                  <button onClick={() => setActiveSectionIndex((prevIndex) => Math.min(prevIndex + 1, sections.length - 1))} className={`flex items-center px-4 py-2 bg-gray-200 dark:bg-gray-700 ${activeSectionIndex === sections.length - 1 && 'opacity-50 cursor-not-allowed'}`} disabled={activeSectionIndex === sections.length - 1}>
                    Next<ChevronRight className="size-4" />
                  </button>
                </div>
              </div>
              {/* Form Content */}
              <div className="space-y-6 p-6">
                {
                  activeSection.id === 'personal' && (
                    <PersonalInfoForm data={resumeData.personal_info || {}} onChange={(data) => setResumeData(prev => ({ ...prev, personal_info: data }))} removeBackground={removeBackground} setRemoveBackground={setRemoveBackground} />
                  )
                }
              </div>


            </div>

          </div>
          {/* Right Panel - Preview */}

          <div className='lg:col-span-7 max-lg:mt-6'>
            <div className="">
              {/* ---buttons ---  */}
            </div>
            <ResumePreview data={resumeData} template={resumeData.template} accentColor={resumeData.accent_color} classes={removeBackground ? 'bg-transparent border-none shadow-none' : ''} />
          </div>
        </div>
      </div>
    </div>
  )
}

export default ResumeBuilder

import { FilePenLineIcon, PencilIcon, PlusIcon, TrashIcon, UploadCloudIcon, XIcon, FileText } from 'lucide-react'
import React, { useState, useEffect } from 'react'
import { DummyResumeData } from '../assets/assets';
import { Link } from 'react-router-dom';
import { useNavigate } from 'react-router-dom';



const Dashboard = () => {
  const colors = ['from-indigo-500 to-blue-500','from-pink-500 to-rose-500','from-purple-500 to-indigo-500','from-orange-500 to-amber-500','from-green-500 to-teal-500'];
  const [allResumes, setAllResumes] = useState([]);
  const [showCreateResume, setshowCreateResume] = useState(false);
  const [showUploadResume, setshowUploadResume] = useState(false);
  const [title, setTitle] = useState('');
  const [resume, setResume] = useState(null);
  const [editResumeId, setEditResumeId] = useState('');
  const navigate = useNavigate();

  const loadAllResumes = async () => {
    // DummyResumeData is an object, but we need an array to map over it.
    // For now, we'll wrap it in an array.
    setAllResumes([DummyResumeData]);
  }

  const createResume = async (event) => {
    event.preventDefault();
    // Logic to create a new resume
    setshowCreateResume(false);
    navigate('/app/builder/res123');
  }

  const uploadResume = async (event) => {
    event.preventDefault();
    // Logic to upload a resume
    setshowUploadResume(false);
    navigate('/app/builder/res123');
  } 
  const editTitle =async (event) => {
    event.preventDefault();
    // Logic to edit the title of a resume
  }

  const deleteResume = async (resumeId) => {
    // Logic to delete a resume
    const confirm = window.confirm('Are you sure you want to delete this resume?');
    if (confirm) {
      setAllResumes(prev => prev.filter(resume => resume._id !== resumeId));
    }
  }

  


  useEffect(() => {
    loadAllResumes();
  }, []);
    
  
  return (
    <div className="bg-slate-50 dark:bg-slate-900 min-h-screen">
      <div className='max-w-7xl mx-auto p-4 sm:p-6 lg:p-8'>
        <div className="mb-8">
          <h1 className='text-3xl font-bold text-slate-800 dark:text-white'>Welcome back, Ravi</h1>
          <p className='text-slate-500 dark:text-slate-400 mt-1'>You have {allResumes.length} resume{allResumes.length !== 1 && 's'}. Let's build your career.</p>
        </div>

        <div className='grid grid-cols-1 sm:grid-cols-2 gap-6'>
          <button onClick={() => setshowCreateResume(true)} className='flex items-center justify-start p-6 bg-white dark:bg-slate-800 rounded-xl shadow-sm hover:shadow-lg transition-shadow border border-gray-200 dark:border-slate-700 group'>
            <div className="p-3 bg-gradient-to-br from-green-400 to-blue-500 text-white rounded-full mr-4 transition-transform group-hover:scale-110">
              <PlusIcon className='size-8'/>
            </div>
            <div>
              <p className='text-lg font-semibold text-gray-800 dark:text-white text-left'>Create New Resume</p>
              <p className='text-sm text-gray-500 dark:text-slate-400 text-left'>Start from scratch with a new template.</p>
            </div>
          </button>
          <button onClick={() => setshowUploadResume(true)} className='flex items-center justify-start p-6 bg-white dark:bg-slate-800 rounded-xl shadow-sm hover:shadow-lg transition-shadow border border-gray-200 dark:border-slate-700 group'>
            <div className="p-3 bg-gradient-to-br from-purple-400 to-pink-500 text-white rounded-full mr-4 transition-transform group-hover:scale-110">
              <UploadCloudIcon className='size-8'/>
            </div>
            <div>
              <p className='text-lg font-semibold text-gray-800 dark:text-white text-left'>Upload Existing</p>
              <p className='text-sm text-gray-500 dark:text-slate-400 text-left'>Import a resume you already have.</p>
            </div>
          </button>
        </div>
        <hr className='my-8 border-slate-200 dark:border-slate-700'/>
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-6">Your Resumes</h2>
        <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'>
          {allResumes.map((resume,index) => {
            const baseColor = colors[index% colors.length];
            return (
              
              <Link to={`/app/builder/${resume._id}`} key={index} className={'relative group flex flex-col justify-between p-6 bg-white dark:bg-slate-800 rounded-xl shadow-sm hover:shadow-lg transition-all border-t-4 border-transparent hover:border-green-500 dark:border-slate-700 dark:hover:border-green-500'} >
                <div className={`absolute top-0 left-0 right-0 h-1 bg-gradient-to-r ${baseColor} rounded-t-lg`}></div>
                <div className="flex items-start">
                  <FileText className={`size-8 mr-4 mt-1 text-slate-400 dark:text-slate-500`}/>
                  <div>
                    <p className='text-lg font-bold text-gray-800 dark:text-white transition-all'>{resume.title}</p>
                    <p className='mt-1 text-xs text-gray-500 dark:text-slate-400'>Last updated: {new Date(resume.updatedAt || Date.now()).toLocaleDateString()}</p>
                  </div>
                </div>
                <div  onClick={e=>e.stopPropagation()} className='absolute top-2 right-2 group-hover:flex hidden flex-col gap-2'>
                  <button onClick={(e)=> {e.preventDefault(); deleteResume(resume._id)}} className='p-2 bg-slate-100 dark:bg-slate-700 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50 group/trash'>
                    <TrashIcon className='size-4 text-slate-500 dark:text-slate-400 group-hover/trash:text-red-500 transition-colors'/>
                  </button>
                  <button onClick={(e)=>{e.preventDefault(); setEditResumeId(resume._id); setTitle (resume.title)}} className='p-2 bg-slate-100 dark:bg-slate-700 rounded-full hover:bg-blue-100 dark:hover:bg-blue-900/50 group/edit'>
                    <PencilIcon className='size-4 text-slate-500 dark:text-slate-400 group-hover/edit:text-blue-500 transition-colors'/>
                  </button>
                </div>
              </Link>
            )
          })}
        </div>  
        {showCreateResume && ( 
          <form onSubmit={createResume} onClick={() => setshowCreateResume(false)}
            className='fixed inset-0 bg-black/70 backdrop-blur bg-opacity-50 z-10
            flex items-center justify-center p-4'>
            <div onClick={e => e.stopPropagation()} className='relative bg-white dark:bg-slate-800
            border dark:border-slate-700 shadow-xl rounded-lg w-full max-w-md p-6'>
              <h2 className='text-xl font-bold mb-4 text-slate-800 dark:text-white'>Create a New Resume</h2>
              <input value={title} type="text" onChange={(e) => setTitle(e.target.value)} placeholder='e.g., "Software Engineer Resume"' className='w-full px-4 py-2 border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-800 dark:text-slate-200 rounded-md mb-4 focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent' required/>
              <button type="submit" className='w-full py-2.5 bg-green-600 text-white font-semibold rounded-md hover:bg-green-700 transition-colors'>Create Resume</button>
              <XIcon className='absolute top-4 right-4 text-slate-400 hover:text-slate-600 dark:hover:text-white cursor-pointer transition-colors' onClick={() => {setshowCreateResume(false); setTitle('')}}/>
            </div>
          </form>
        )}
        {showUploadResume &&(
          <form onSubmit={uploadResume} onClick={() => setshowUploadResume(false)}
            className='fixed inset-0 bg-black/70 backdrop-blur bg-opacity-50 z-10
            flex items-center justify-center p-4'>
            <div onClick={e => e.stopPropagation()} className='relative bg-white dark:bg-slate-800
            border dark:border-slate-700 shadow-xl rounded-lg w-full max-w-md p-6'>
              <h2 className='text-xl font-bold mb-4 text-slate-800 dark:text-white'>Upload an Existing Resume</h2>
              <input value={title} type="text"  onChange={(e) => setTitle(e.target.value)} placeholder='e.g., "My Imported Resume"' className='w-full px-4 py-2 border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-800 dark:text-slate-200 rounded-md mb-4 focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent' required/>
              <div className="mb-4">
                <label htmlFor='resume-input' className="cursor-pointer">
                  <div className='flex flex-col items-center justify-center w-full h-32 text-slate-500 dark:text-slate-400 border-2 border-slate-300 dark:border-slate-600 border-dashed rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors'>
                    {
                      resume ?(
                        <p className='font-medium text-green-600'>
                          {resume.name}
                        </p>
                      ):(
                        <>
                        <UploadCloudIcon className='size-8 mb-2 stroke-1'/>
                        <p className="font-semibold">Click to upload a file</p>
                        <p className="text-xs">PDF up to 5MB</p>
                        </>
                      )
                    }
                  </div>
                </label>

                <input type='file' id='resume-input' className='hidden' accept='.pdf' onChange={(e) => setResume(e.target.files[0])}/>
              </div>
              <button type="submit" className='w-full py-2.5 bg-green-600 text-white font-semibold rounded-md hover:bg-green-700 transition-colors'>Upload Resume</button>
              <XIcon className='absolute top-4 right-4 text-slate-400 hover:text-slate-600 dark:hover:text-white cursor-pointer transition-colors' onClick={() => {setshowUploadResume(false); setTitle('')}}/>
            </div>
          </form>
        )
        }

        {editResumeId && ( 
          <form onSubmit={editTitle} onClick={() => setEditResumeId('')}
            className='fixed inset-0 bg-black/70 backdrop-blur bg-opacity-50 z-10
            flex items-center justify-center p-4'>
            <div onClick={e => e.stopPropagation()} className='relative bg-white dark:bg-slate-800
            border dark:border-slate-700 shadow-xl rounded-lg w-full max-w-md p-6'>
              <h2 className='text-xl font-bold mb-4 text-slate-800 dark:text-white'>Edit Resume Title</h2>
              <input value={title} type="text" onChange={(e) => setTitle(e.target.value)} placeholder='e.g., "Software Engineer Resume"' className='w-full px-4 py-2 border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-800 dark:text-slate-200 rounded-md mb-4 focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent' required/>
              <button type="submit" className='w-full py-2.5 bg-green-600 text-white font-semibold rounded-md hover:bg-green-700 transition-colors'>Update</button>
              <XIcon className='absolute top-4 right-4 text-slate-400 hover:text-slate-600 dark:hover:text-white cursor-pointer transition-colors' onClick={() => {setEditResumeId(''); setTitle('')}}/>
            </div>
          </form>
        )}

      </div>
    </div>
  )
}

export default Dashboard
